external_knowledge:
- A higher rating indicates better performance under stress; 
- The formula for the rating, repetitions_to_failure * stress_strength_ratio / total_concrete_stress, represents a measure of the pavement's ability to withstand stress before failing;
- The average cost of all maintenance history entries serves as a benchmark to filter pavement metrics.

sql:
SELECT AVG(pavement_damage) AS average_pavement_damage, site_id
FROM pavement_metrics
GROUP BY site_id;

SELECT AVG(pavement_damage) AS average_damage
FROM pavement_metrics
WHERE traffic_volume > 1800;

SELECT MAX(maintenance_date) AS last_inspection_date
FROM maintenance_history
WHERE site_id = 1;

SELECT DISTINCT site_id, pavement_damage, cumulative_damage, punchouts_per_mile
FROM pavement_metrics
WHERE cumulative_damage > 0.05 AND punchouts_per_mile > 0.05;
